          assert MaxOf(a', b') == b';
          assert MaxOf(b', c') == b';
          assert x == b' && z == b';
        } else {
          // c' is largest: MaxOf(a',c')=c'=y, MaxOf(b',c')=c'=z, so y==z
          assert c' >= a' && c' >= b';
          assert MaxOf(a', c') == c';
